ValidationRule.errorConditionFormula:
OR(

    /* Début le week-end */
    WEEKDAY(Date_de_debut__c) = 1,
    WEEKDAY(Date_de_debut__c) = 7,

    /* Fin le week-end */
    WEEKDAY(Date_de_fin__c) = 1,
    WEEKDAY(Date_de_fin__c) = 7,

    /* Fin avant début */
    Date_de_fin__c < Date_de_debut__c,

    /* Fin après le vendredi de la semaine du début */
     Date_de_fin__c >
    (
         Date_de_debut__c
        + (6 - WEEKDAY(Date_de_debut__c))
    )
)
